/**
 * Canvas 2D paper-doll renderer for dialogue portrait dressup.
 *
 * The renderer consumes launcher/web/assets/dressup/manifest.json, which is
 * generated by tools/bake-dressup-offline.py from data/items and the dialogue
 * XFL rig. Baked frames carry registration-point offsets exported from FFDec
 * SVG metadata, so Canvas drawing preserves Flash attachMovie origin behavior.
 */
var DressupDollRenderer = (function() {
    'use strict';

    var FIELD_COLORS = {
        '身体': '#648fff',
        '上臂': '#785ef0',
        '左下臂': '#dc267f',
        '右下臂': '#dc267f',
        '左手': '#fe6100',
        '右手': '#fe6100',
        '屁股': '#ffb000',
        '左大腿': '#4db05a',
        '右大腿': '#4db05a',
        '小腿': '#2a9d8f',
        '脚': '#9c755f',
        '脸型': '#e8c1a0',
        '发型': '#8f6b32',
        '面具': '#b56576',
        '刀_装扮': '#d62828',
        '刀1_装扮': '#d62828',
        '刀2_装扮': '#b21e35',
        '刀3_装扮': '#8c1d40',
        '长枪_装扮': '#277da1',
        '手枪_装扮': '#577590',
        '手枪2_装扮': '#577590',
        '手雷_装扮': '#6d597a'
    };

    var PLACEHOLDER_W = 64;
    var PLACEHOLDER_H = 42;
    if (typeof AssetTimeline === 'undefined' || !AssetTimeline) {
        throw new Error('AssetTimeline must be loaded before dressup-doll-renderer.js');
    }
    var Timeline = AssetTimeline;

    function loadManifest(url) {
        return fetch(url).then(function(response) {
            if (!response.ok) throw new Error('Failed to load dressup manifest: ' + response.status);
            return response.json();
        }).then(function(data) {
            data.__baseUrl = new URL(url, document.baseURI).href;
            return data;
        });
    }

    function collectItemsByUse(manifest) {
        var byUse = {};
        var items = manifest && manifest.items ? manifest.items : {};
        Object.keys(items).sort().forEach(function(name) {
            var item = items[name];
            var use = item.use || '<unknown>';
            if (!byUse[use]) byUse[use] = [];
            byUse[use].push(name);
        });
        return byUse;
    }

    function mergeFields(target, fields) {
        if (!fields) return;
        Object.keys(fields).forEach(function(field) {
            target[field] = fields[field];
        });
    }

    function buildStateFromEquipment(manifest, options) {
        options = options || {};
        var gender = options.gender || '男';
        var keyMap = {};
        var equipment = options.equipment || {};
        Object.keys(equipment).forEach(function(slot) {
            var itemName = equipment[slot];
            var item = manifest.items[itemName];
            if (item && item.fieldsByGender) {
                mergeFields(keyMap, item.fieldsByGender[gender]);
            }
        });
        mergeFields(keyMap, options.appearance);
        mergeFields(keyMap, options.keyMap);
        return {
            gender: gender,
            keyMap: keyMap
        };
    }

    function matrixOf(holder) {
        var m = holder.matrix || {};
        return matrixFrom(m);
    }

    function matrixFrom(value) {
        var m = value || {};
        return {
            a: numberOr(m.a, 1),
            b: numberOr(m.b, 0),
            c: numberOr(m.c, 0),
            d: numberOr(m.d, 1),
            tx: numberOr(m.tx, 0),
            ty: numberOr(m.ty, 0)
        };
    }

    function multiplyMatrix(left, right) {
        return {
            a: left.a * right.a + left.c * right.b,
            b: left.b * right.a + left.d * right.b,
            c: left.a * right.c + left.c * right.d,
            d: left.b * right.c + left.d * right.d,
            tx: left.a * right.tx + left.c * right.ty + left.tx,
            ty: left.b * right.tx + left.d * right.ty + left.ty
        };
    }

    function numberOr(value, fallback) {
        return typeof value === 'number' && isFinite(value) ? value : fallback;
    }

    function expandBounds(bounds, x, y) {
        bounds.minX = Math.min(bounds.minX, x);
        bounds.minY = Math.min(bounds.minY, y);
        bounds.maxX = Math.max(bounds.maxX, x);
        bounds.maxY = Math.max(bounds.maxY, y);
    }

    function skinZoom(skin) {
        if (!skin || !skin.export) return 1;
        var zoom = numberOr(skin.export.zoom, 1);
        return zoom > 0 ? zoom : 1;
    }

    function frameDrawSize(skin, frame) {
        if (!skin || !skin.export) return { width: PLACEHOLDER_W, height: PLACEHOLDER_H };
        var zoom = skinZoom(skin);
        frame = frame || {};
        return {
            width: Math.max(1, numberOr(frame.width, numberOr(skin.export.width, PLACEHOLDER_W * zoom)) / zoom),
            height: Math.max(1, numberOr(frame.height, numberOr(skin.export.height, PLACEHOLDER_H * zoom)) / zoom)
        };
    }

    function frameOrigin(skin, frame) {
        if (!skin || !skin.export || !frame) return { x: 0, y: 0 };
        var zoom = skinZoom(skin);
        return {
            x: numberOr(frame.originX, 0) / zoom,
            y: numberOr(frame.originY, 0) / zoom
        };
    }

    function playbackFrames(entry) {
        return Timeline.playbackFrames(entry);
    }

    function skinBoundsSize(skin) {
        if (!skin || !skin.export) return { width: PLACEHOLDER_W, height: PLACEHOLDER_H };
        var frames = playbackFrames(skin);
        if (!frames.length) return frameDrawSize(skin, null);
        var maxWidth = 1;
        var maxHeight = 1;
        frames.forEach(function(frame) {
            var size = frameDrawSize(skin, frame);
            maxWidth = Math.max(maxWidth, size.width);
            maxHeight = Math.max(maxHeight, size.height);
        });
        return { width: maxWidth, height: maxHeight };
    }

    function nestedLayers(entry, drawOrder) {
        var nested = entry && entry.export && entry.export.nestedAnimation;
        var layers = nested && nested.layers ? nested.layers : [];
        if (!drawOrder) return layers;
        return layers.filter(function(layer) {
            return (layer.drawOrder || 'over') === drawOrder;
        });
    }

    function renderableForHolder(holder, manifest, keyMap) {
        var skinKey = keyMap ? keyMap[holder.field] : null;
        var skin = skinKey && manifest.skinKeys ? manifest.skinKeys[skinKey] : null;
        if (skin && skin.export) {
            return {
                kind: 'skin',
                key: skinKey,
                entry: skin,
                innerMatrix: null,
                covered: skin.covered
            };
        }
        if ((!skin || skin.covered === false) && holder.fallbackBasic && holder.basic && holder.basic.export) {
            return {
                kind: 'basic',
                key: holder.basic.linkageId || holder.basic.libraryItemName || holder.field,
                entry: holder.basic,
                innerMatrix: matrixFrom(holder.basic.matrix),
                covered: true
            };
        }
        return {
            kind: 'missing',
            key: skinKey,
            entry: null,
            innerMatrix: null,
            covered: skin ? skin.covered : false
        };
    }

    function matrixForRenderable(holder, renderable) {
        var matrix = matrixOf(holder);
        if (renderable && renderable.innerMatrix) {
            matrix = multiplyMatrix(matrix, renderable.innerMatrix);
        }
        return matrix;
    }

    function expandEntryBounds(bounds, entry, matrix) {
        if (!entry) return;
        var m = matrix;
        var frames = playbackFrames(entry);
        frames = frames.length ? frames : [null];
        frames.forEach(function(frame) {
            var drawSize = frameDrawSize(entry, frame);
            var origin = frameOrigin(entry, frame);
            var left = -origin.x;
            var top = -origin.y;
            var right = left + drawSize.width;
            var bottom = top + drawSize.height;
            var corners = [
                [left, top],
                [right, top],
                [left, bottom],
                [right, bottom]
            ];
            corners.forEach(function(point) {
                var x = m.a * point[0] + m.c * point[1] + m.tx;
                var y = m.b * point[0] + m.d * point[1] + m.ty;
                expandBounds(bounds, x, y);
            });
        });
    }

    function expandNestedLayerBounds(bounds, layer, parentMatrix) {
        if (!layer || !layer.export) return;
        var matrix = multiplyMatrix(parentMatrix, matrixFrom(layer.matrix));
        nestedLayers(layer).forEach(function(childLayer) {
            expandNestedLayerBounds(bounds, childLayer, matrix);
        });
        expandEntryBounds(bounds, layer, matrix);
    }

    function computeBounds(holders, manifest, keyMap, debugPlaceholders) {
        var bounds = { minX: Infinity, minY: Infinity, maxX: -Infinity, maxY: -Infinity };
        holders.forEach(function(holder) {
            var renderable = renderableForHolder(holder, manifest, keyMap);
            if (!renderable.entry && !debugPlaceholders) return;
            var m = matrixForRenderable(holder, renderable);
            if (renderable.entry) {
                nestedLayers(renderable.entry).forEach(function(layer) {
                    expandNestedLayerBounds(bounds, layer, m);
                });
                expandEntryBounds(bounds, renderable.entry, m);
                return;
            }
            var frames = renderable.entry && renderable.entry.frames && renderable.entry.frames.length
                ? renderable.entry.frames
                : [null];
            frames.forEach(function(frame) {
                var drawSize = renderable.entry ? frameDrawSize(renderable.entry, frame) : { width: PLACEHOLDER_W, height: PLACEHOLDER_H };
                var origin = renderable.entry ? frameOrigin(renderable.entry, frame) : { x: 0, y: 0 };
                var left = -origin.x;
                var top = -origin.y;
                var right = left + drawSize.width;
                var bottom = top + drawSize.height;
                var corners = [
                    [left, top],
                    [right, top],
                    [left, bottom],
                    [right, bottom]
                ];
                corners.forEach(function(point) {
                    var x = m.a * point[0] + m.c * point[1] + m.tx;
                    var y = m.b * point[0] + m.d * point[1] + m.ty;
                    expandBounds(bounds, x, y);
                });
            });
        });
        if (!isFinite(bounds.minX)) {
            bounds = { minX: -80, minY: -120, maxX: 180, maxY: 280 };
        }
        return bounds;
    }

    function resolveImageUri(uri, manifest) {
        if (!uri) return null;
        if (/^(https?:|data:|blob:|\/)/.test(uri)) return uri;
        return new URL(uri, manifest.__baseUrl || document.baseURI).href;
    }

    function selectSkinFrame(skin, nowMs, fallbackFps) {
        if (!skin) return { frame: null, animated: false };
        var frames = playbackFrames(skin);
        if (!frames.length) {
            return {
                frame: skin.export ? { uri: skin.export.uri, width: skin.export.width, height: skin.export.height } : null,
                animated: false
            };
        }
        return Timeline.select(skin, nowMs, {
            frames: frames,
            fallbackFps: fallbackFps,
            defaultFps: fallbackFps,
            identity: ['uri', 'width', 'height', 'originX', 'originY']
        });
    }

    function createImageCache() {
        return {};
    }

    function loadImage(cache, uri, onload) {
        if (!uri) return null;
        if (cache[uri]) return cache[uri];
        var image = new Image();
        cache[uri] = image;
        image.onload = onload;
        image.onerror = onload;
        image.src = uri;
        return image;
    }

    function drawPlaceholder(ctx, holder, skinKey, covered) {
        var color = FIELD_COLORS[holder.field] || '#6c757d';
        ctx.save();
        ctx.globalAlpha = covered === false ? 0.38 : 0.78;
        ctx.fillStyle = color;
        ctx.strokeStyle = 'rgba(255,255,255,0.78)';
        ctx.lineWidth = 1;
        roundedRect(ctx, 0, 0, PLACEHOLDER_W, PLACEHOLDER_H, 4);
        ctx.fill();
        ctx.stroke();
        ctx.globalAlpha = 1;
        ctx.fillStyle = '#ffffff';
        ctx.font = '8px "Microsoft YaHei", Arial, sans-serif';
        ctx.textBaseline = 'top';
        ctx.fillText(holder.field, 4, 4);
        ctx.fillStyle = 'rgba(255,255,255,0.82)';
        ctx.font = '6px "Microsoft YaHei", Arial, sans-serif';
        wrapText(ctx, skinKey || '(empty)', 4, 17, PLACEHOLDER_W - 8, 8, 2);
        ctx.restore();
    }

    function roundedRect(ctx, x, y, w, h, r) {
        ctx.beginPath();
        ctx.moveTo(x + r, y);
        ctx.lineTo(x + w - r, y);
        ctx.quadraticCurveTo(x + w, y, x + w, y + r);
        ctx.lineTo(x + w, y + h - r);
        ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
        ctx.lineTo(x + r, y + h);
        ctx.quadraticCurveTo(x, y + h, x, y + h - r);
        ctx.lineTo(x, y + r);
        ctx.quadraticCurveTo(x, y, x + r, y);
        ctx.closePath();
    }

    function wrapText(ctx, text, x, y, maxWidth, lineHeight, maxLines) {
        var line = '';
        var lines = 0;
        for (var i = 0; i < text.length; i++) {
            var next = line + text.charAt(i);
            if (ctx.measureText(next).width > maxWidth && line) {
                ctx.fillText(line, x, y + lines * lineHeight);
                line = text.charAt(i);
                lines++;
                if (lines >= maxLines) return;
            } else {
                line = next;
            }
        }
        if (line && lines < maxLines) ctx.fillText(line, x, y + lines * lineHeight);
    }

    function applyMatrix(ctx, matrix) {
        var m = matrix.a === undefined ? matrixOf(matrix) : matrix;
        ctx.transform(m.a, m.b, m.c, m.d, m.tx, m.ty);
    }

    function drawFrameImage(ctx, entry, frame, image) {
        var drawSize = frameDrawSize(entry, frame);
        var origin = frameOrigin(entry, frame);
        ctx.drawImage(image, -origin.x, -origin.y, drawSize.width, drawSize.height);
    }

    function create(canvas, options) {
        options = options || {};
        var ctx = canvas.getContext('2d');
        var manifest = options.manifest;
        var imageCache = createImageCache();
        var lastState = null;
        var animationRequest = null;
        var destroyed = false;
        var fallbackFps = numberOr(options.fps, 24);
        var debugPlaceholders = options.debugPlaceholders === true;

        function scheduleAnimation() {
            if (destroyed) return;
            if (animationRequest) return;
            animationRequest = window.requestAnimationFrame(function() {
                animationRequest = null;
                if (!destroyed && lastState) render(lastState);
            });
        }

        function setupCanvas() {
            var dpr = window.devicePixelRatio || 1;
            var rect = canvas.getBoundingClientRect();
            var cssW = Math.max(1, Math.round(rect.width || options.width || 360));
            var cssH = Math.max(1, Math.round(rect.height || options.height || 520));
            if (canvas.width !== Math.round(cssW * dpr) || canvas.height !== Math.round(cssH * dpr)) {
                canvas.width = Math.round(cssW * dpr);
                canvas.height = Math.round(cssH * dpr);
            }
            ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
            ctx.clearRect(0, 0, cssW, cssH);
            return { width: cssW, height: cssH, dpr: dpr };
        }

        function render(state) {
            if (destroyed) return null;
            lastState = state || lastState || { gender: '男', keyMap: {} };
            var nowMs = window.performance && window.performance.now ? window.performance.now() : Date.now();
            var size = setupCanvas();
            var gender = lastState.gender || '男';
            var rigGender = manifest.rig && manifest.rig.genders ? manifest.rig.genders[gender] : null;
            var holders = rigGender ? rigGender.holders || [] : [];
            var bounds = computeBounds(holders, manifest, lastState.keyMap, debugPlaceholders);
            var margin = 24;
            var w = Math.max(1, bounds.maxX - bounds.minX);
            var h = Math.max(1, bounds.maxY - bounds.minY);
            var scale = Math.min((size.width - margin * 2) / w, (size.height - margin * 2) / h);
            scale = Math.max(0.1, Math.min(3, scale * (options.zoom || 0.92)));
            var offsetX = (size.width - (bounds.minX + bounds.maxX) * scale) / 2;
            var offsetY = (size.height - (bounds.minY + bounds.maxY) * scale) / 2;

            ctx.save();
            ctx.translate(offsetX, offsetY);
            ctx.scale(scale, scale);
            var needsAnimation = false;
            var missing = 0;
            function drawLayer(layer, nowMs) {
                if (!layer || !layer.export) return;
                var selected = selectSkinFrame(layer, nowMs, fallbackFps);
                needsAnimation = needsAnimation || selected.animated;
                var frame = selected.frame;
                var uri = resolveImageUri(frame && frame.uri, manifest);
                var image = loadImage(imageCache, uri, function() { render(lastState); });
                if (!image || !image.complete || image.naturalWidth <= 0) return;
                ctx.save();
                applyMatrix(ctx, matrixFrom(layer.matrix));
                nestedLayers(layer, 'under').forEach(function(childLayer) {
                    drawLayer(childLayer, nowMs);
                });
                drawFrameImage(ctx, layer, frame, image);
                nestedLayers(layer, 'over').forEach(function(childLayer) {
                    drawLayer(childLayer, nowMs);
                });
                ctx.restore();
            }
            holders.forEach(function(holder) {
                var renderable = renderableForHolder(holder, manifest, lastState.keyMap);
                if (!renderable.entry) {
                    if (renderable.key) missing++;
                    if (!debugPlaceholders) return;
                }
                var selected = selectSkinFrame(renderable.entry, nowMs, fallbackFps);
                needsAnimation = needsAnimation || selected.animated;
                var frame = selected.frame;
                var uri = resolveImageUri(frame && frame.uri, manifest);
                var image = loadImage(imageCache, uri, function() { render(lastState); });
                ctx.save();
                applyMatrix(ctx, matrixForRenderable(holder, renderable));
                if (renderable.entry) {
                    nestedLayers(renderable.entry, 'under').forEach(function(layer) {
                        drawLayer(layer, nowMs);
                    });
                }
                if (renderable.entry && image && image.complete && image.naturalWidth > 0) {
                    drawFrameImage(ctx, renderable.entry, frame, image);
                } else if (debugPlaceholders) {
                    drawPlaceholder(ctx, holder, renderable.key, renderable.covered);
                }
                if (renderable.entry) {
                    nestedLayers(renderable.entry, 'over').forEach(function(layer) {
                        drawLayer(layer, nowMs);
                    });
                }
                ctx.restore();
            });
            ctx.restore();
            if (needsAnimation) scheduleAnimation();
            return {
                gender: gender,
                holders: holders.length,
                bounds: bounds,
                scale: scale,
                animated: needsAnimation,
                missing: missing
            };
        }

        return {
            render: render,
            setManifest: function(nextManifest) { manifest = nextManifest; },
            getManifest: function() { return manifest; },
            destroy: function() {
                destroyed = true;
                lastState = null;
                if (animationRequest) {
                    window.cancelAnimationFrame(animationRequest);
                    animationRequest = null;
                }
            }
        };
    }

    return {
        loadManifest: loadManifest,
        collectItemsByUse: collectItemsByUse,
        buildStateFromEquipment: buildStateFromEquipment,
        create: create
    };
})();
